def resolve_input_path() -> str:
    for path in DEFAULT_INPUT_PATHS:
        if os.path.exists(path):
            return path
    raise FileNotFoundError(f"No input file found in: {DEFAULT_INPUT_PATHS}")


def strip_code_fences(text: str) -> str:
    cleaned = (text or "").strip()
    match = re.match(r"^```(?:json)?\s*(.*?)\s*```$", cleaned, flags=re.DOTALL | re.IGNORECASE)
    if match:
        return match.group(1).strip()
    return cleaned


def normalize_exam_name(name: str) -> str:
    return re.sub(r"\s+", " ", str(name or "").strip())


def normalize_exam_result(value: Any) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def canonical_text(text: str) -> str:
    lowered = str(text or "").lower()
    return re.sub(r"[^a-z0-9\u4e00-\u9fff]+", "", lowered)


def normalize_top_level_key(text: str) -> str:
    lowered = str(text or "").strip().lower()
    lowered = re.sub(r"[^a-z0-9]+", "_", lowered)
    lowered = re.sub(r"_+", "_", lowered).strip("_")
    return lowered or "field"


def get_item_value(item: Dict[str, Any], *candidate_keys: str) -> Any:
    normalized_candidates = {normalize_top_level_key(key) for key in candidate_keys}
    for key, value in item.items():
        if normalize_top_level_key(key) in normalized_candidates:
            return value
    return ""


def dedupe_semantic_items(items: List[str]) -> List[str]:
    seen = set()
    out: List[str] = []
    for item in items:
        clean = normalize_exam_name(item)
        key = canonical_text(clean)
        if not clean or not key or key in seen:
            continue
        seen.add(key)
        out.append(clean)
    return out


def split_exam_name_candidates(text: str) -> List[str]:
    normalized = re.sub(r"\s*,\s*and\s+", ", ", str(text or "").strip(), flags=re.IGNORECASE)
    normalized = re.sub(r"\s+and\s+", ", ", normalized)
    parts = [part.strip() for part in normalized.split(",") if part.strip()]
    return parts


def expand_structured_exams(exams: Dict[str, str]) -> Dict[str, str]:
    expanded: Dict[str, str] = {}

    for exam_name, exam_result in exams.items():
        normalized_name = normalize_exam_name(exam_name)
        normalized_result = normalize_exam_result(exam_result)
        lower_name = normalized_name.lower()

        if lower_name.startswith("immunohistochemistry for "):
            marker_text = normalized_name[len("Immunohistochemistry for ") :]
            markers = split_exam_name_candidates(marker_text)
            if len(markers) > 1:
                for marker in markers:
                    expanded[f"Immunohistochemistry for {marker}"] = normalized_result
                continue

        expanded[normalized_name] = normalized_result

    return expanded


def validate_model_output(obj: Dict[str, Any]) -> Dict[str, Any]:
    exam_dict = obj.get("structured_exams")
    distractors = obj.get("distractor_tests")

    if not isinstance(exam_dict, dict):
        raise ValueError("structured_exams must be a dict")
    if not isinstance(distractors, list):
        raise ValueError("distractor_tests must be a list")

    normalized_exams: Dict[str, str] = {}
    for raw_key, raw_value in exam_dict.items():
        key = normalize_exam_name(raw_key)
        value = normalize_exam_result(raw_value)
        if not key or not value:
            continue
        normalized_exams[key] = value

    normalized_exams = expand_structured_exams(normalized_exams)

    if not normalized_exams:
        raise ValueError("structured_exams is empty after normalization")

    exam_keys = {canonical_text(k) for k in normalized_exams.keys()}
    normalized_distractors = dedupe_semantic_items([str(x) for x in distractors])
    filtered_distractors = [
        x
        for x in normalized_distractors
        if canonical_text(x) not in exam_keys and canonical_text(x) not in GENERIC_DISTRACTOR_HINTS
    ]

    if len(filtered_distractors) < 10:
        raise ValueError("fewer than 10 distractor tests remain after dedupe")

    return {
        "structured_exams": normalized_exams,
        "distractor_tests": filtered_distractors[:15],
    }


def parse_structured_output(text: str) -> Dict[str, Any]:
    cleaned = strip_code_fences(text)
    obj = json.loads(cleaned)
    return validate_model_output(obj)


