def call_model_with_retry(client: OpenAI, model: str, messages: List[Dict[str, Any]], max_retries: int = 2) -> Dict[str, Any]:
    local_messages = list(messages)
    last_error = ""
    for i in range(max_retries + 1):
        resp = client.chat.completions.create(model=model, messages=local_messages, max_completion_tokens=30000)
        text = resp.choices[0].message.content or ""
        try:
            return parse_structured_output(text)
        except Exception as exc:
            last_error = f"{type(exc).__name__}: {exc}"
            if i < max_retries:
                local_messages = local_messages + [
                    {
                        "role": "user",
                        "content": (
                            "Format error. Reply with JSON only. "
                            "Keep structured_exams as a non-empty dictionary with specific exam names, "
                            "split overly broad combined exams into finer keys when supported, "
                            "and keep distractor_tests as at least 10 concrete, high-confusion tests that are not the same as existing exams and are not generic screening labs. "
                            f"Last validation error: {last_error}"
                        ),
                    }
                ]
    raise ValueError(f"Failed to parse model output after retries: {last_error}")


